import React from 'react';

function DottedSphere({ size = 600, className = '' }) {
  return (
    <div className={`absolute pointer-events-none ${className}`} style={{
      width: size,
      height: size,
    }}>
      <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
        <defs>
          <radialGradient id="dotGradient" cx="50%" cy="50%" r="50%">
            <stop offset="0%" stopColor="#8b5cf6" stopOpacity="0.6" />
            <stop offset="50%" stopColor="#6366f1" stopOpacity="0.5" />
            <stop offset="100%" stopColor="#38bdf8" stopOpacity="0.3" />
          </radialGradient>
        </defs>
        {Array.from({ length: 20 }).map((_, ring) => {
          const radius = (ring / 20) * (size / 2 - 20) + 30;
          const numDots = Math.floor(12 + ring * 3.5);
          return Array.from({ length: numDots }).map((_, i) => {
            const angle = (i / numDots) * Math.PI * 2 + (ring * 0.2);
            const x = Math.cos(angle) * radius + size / 2;
            const y = Math.sin(angle) * radius + size / 2;
            const dotSize = 1.5 + (ring / 20) * 1.5;
            const opacity = 0.4 + (ring / 20) * 0.4;
            return (
              <circle
                key={`${ring}-${i}`}
                cx={x}
                cy={y}
                r={dotSize}
                fill="url(#dotGradient)"
                opacity={opacity}
              />
            );
          });
        })}
      </svg>
    </div>
  );
}

export default DottedSphere;
